            net += area
            count += 1
        elif isinstance(e, WallOpeningElem) and e.host_wall_id == wall.id:
            width = (e.along_t_end - e.along_t_start) * wall_len_mm
            height = e.head_height_mm - e.sill_height_mm
            area = width * height / 1_000_000.0
            gross += area
            net += area
            count += 1
